const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Set up file upload configuration
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    const uploadDir = 'public/uploads';
    if (!fs.existsSync(uploadDir)) fs.mkdirSync(uploadDir);
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    cb(null, Date.now() + path.extname(file.originalname));
  }
});

const upload = multer({
  storage,
  limits: { fileSize: null }, // No size limit for enterprise users
  fileFilter(req, file, cb) {
    const allowedExtensions = ['jpg', 'png', 'gif', 'svg', 'pdf', 'doc', 'docx', 'zip'];
    const extension = path.extname(file.originalname).toLowerCase();
    if (allowedExtensions.includes(extension)) return cb(null, true);
    return cb(new Error('File type not supported'));
  }
});

// File upload endpoint
app.post('/upload', upload.array('files'), (req, res) => {
  try {
    const files = req.files;
    for (const file of files) {
      if (file.mimetype.startsWith('image/')) {
        // Generate thumbnail
        const filename = file.filename;
        const thumbFilename = `${filename}-thumb.${path.extname(filename)}`;
        const thumbPath = path.join('public/uploads/thumbs', thumbFilename);
        fs.copyFileSync(file.path, thumbPath);
      }
    }
    res.json({ message: 'Files uploaded successfully' });
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error uploading files' });
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});